const babelTypes = require('@babel/types');

const { IMPORT_TYPES } = require('../../../../constants/islands');

/**
 * @param {babelTypes.BlockStatement} fnBody
 * @param {{ varNames: Record<string,string>, isObjectPattern: boolean }} varInfo
 * @returns {string?} Import name
 */
const lookForImportInFunctionBody = (
  { body },
  { varNames, isObjectPattern },
) => {
  const { argument } =
    body.find(
      (statement) =>
        babelTypes.isReturnStatement(statement) &&
        ((babelTypes.isMemberExpression(statement.argument) &&
          babelTypes.isIdentifier(statement.argument.object)) ||
          babelTypes.isIdentifier(statement.argument)),
    ) || {};

  if (!argument) {
    return null;
  }

  if (
    babelTypes.isMemberExpression(argument) &&
    varNames[argument.object.name]
  ) {
    if (isObjectPattern) {
      return argument.object.name;
    }

    return babelTypes.isIdentifier(argument.property) && !argument.computed
      ? argument.property.name
      : IMPORT_TYPES.DEFAULT;
  }

  if (babelTypes.isIdentifier(argument) && varNames[argument.name]) {
    return isObjectPattern ? argument.name : IMPORT_TYPES.DEFAULT;
  }

  return null;
};

/**
 * @param {babelTypes.ArrowFunctionExpression | babelTypes.FunctionExpression | null | undefined} resolveNode
 * @returns {string?} Import name
 */
const searchImportName = (resolveNode) => {
  if (!resolveNode) {
    return null;
  }

  if (!resolveNode.params.length) {
    return null;
  }

  const componentsVarNames = {};

  let isObjectPattern = false;

  // is "({ component1, component2, ... }) => ..." or "function ({ component1, component2, ... }) {...}"
  if (babelTypes.isObjectPattern(resolveNode.params[0])) {
    isObjectPattern = true;

    resolveNode.params[0].properties.forEach((property) => {
      if (
        !babelTypes.isObjectProperty(property) ||
        !babelTypes.isIdentifier(property.key) ||
        !babelTypes.isIdentifier(property.value)
      ) {
        return;
      }

      componentsVarNames[property.value.name] = property.key.name;
    });
  }

  // is "(componentsVar) => ..." or "function(componentsVar) {...}"
  if (babelTypes.isIdentifier(resolveNode.params[0])) {
    componentsVarNames[resolveNode.params[0].name] = resolveNode.params[0].name;
  }

  if (
    babelTypes.isArrowFunctionExpression(resolveNode) &&
    (babelTypes.isMemberExpression(resolveNode.body) ||
      babelTypes.isIdentifier(resolveNode.body))
  ) {
    // example 1: "(components) => components.myComponent;"
    // example 2: "(components, i) => components[i];"
    if (babelTypes.isMemberExpression(resolveNode.body)) {
      if (
        !babelTypes.isIdentifier(resolveNode.body.object) ||
        !componentsVarNames[resolveNode.body.object.name]
      ) {
        return null;
      }

      if (isObjectPattern) {
        return resolveNode.body.object.name;
      }

      return babelTypes.isIdentifier(resolveNode.body.property) &&
        !resolveNode.body.computed
        ? resolveNode.body.property.name
        : IMPORT_TYPES.DEFAULT;
    }

    // example 1: "(myComponent) => myComponent;"
    // example 2: "(myComponent, i) => myComponent;"
    if (
      babelTypes.isIdentifier(resolveNode.body) &&
      componentsVarNames[resolveNode.body.name]
    ) {
      return isObjectPattern ? resolveNode.body.name : IMPORT_TYPES.DEFAULT;
    }

    return null;
  }

  if (!babelTypes.isBlockStatement(resolveNode.body)) {
    return null;
  }

  // example 1: "(components) => { return components.myComponent; }"
  // example 2: "(components, i) => { return components[i]; }"
  // example 3: "(components) => { return components; }"
  // example 4: "(components, i) => { return components; }"
  // example 5: "({ component1 }) => { return component1; }"
  // example 6: "({ component1: c1 }) => { return c1; }"
  // example 7: "function (components) { return components.myComponent; }"
  // example 8: "function (components, i) { return components[i]; }"
  // example 9: "function (components) { return components; }"
  // example 10: "function (components, i) { return components; }"
  // example 11: "function ({ component1 }) { return component1; }"
  // example 12: "function ({ component1: c1 }) { return c1; }"
  return lookForImportInFunctionBody(resolveNode.body, {
    varNames: componentsVarNames,
    isObjectPattern,
  });
};

module.exports = {
  searchImportName,
};
